-- Enrichment marathon batch: BigQuery, Bill.com, Bill4Time, Billsby, Birdeye, Bitdefender, bitmagnet, bittorrent-tracker

-- ── BigQuery ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Google Cloud's serverless, highly scalable data warehouse for running fast SQL analytics and machine learning over massive datasets without managing infrastructure.$q$, short_description),
  pricing_model = COALESCE($q$Usage-based$q$, pricing_model),
  starting_price = COALESCE($q$Free (1 TiB queries + 10 GB storage/month free tier)$q$, starting_price),
  founded_year = COALESCE(2010, founded_year),
  company_size = COALESCE($q$Alphabet/Google Cloud (100,000+ employees company-wide)$q$, company_size),
  headquarters = COALESCE($q$Mountain View, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$BigQuery: Pricing, Features & Review 2026$q$, seo_title),
  seo_meta_description = COALESCE($q$BigQuery is Google Cloud's serverless data warehouse. See 2026 pricing, on-demand vs capacity models, key features, pros, cons, and FAQs.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$BigQuery is Google Cloud's fully managed, serverless enterprise data warehouse, announced at Google I/O in May 2010 and made generally available in November 2011. It grew out of Dremel, an internal Google query engine, and lets users run SQL queries over datasets ranging from gigabytes to petabytes without provisioning or managing servers. Google Cloud (a division of Alphabet Inc.) is headquartered in Mountain View, California. BigQuery separates storage and compute: data is stored in a columnar, nested/repeated format, and compute is billed independently, either on-demand (per terabyte of data scanned) or through flat-rate/autoscaling 'editions' (Standard, Enterprise, Enterprise Plus) that reserve compute capacity for predictable workloads. As of 2026, on-demand querying costs roughly $6.25 per TiB processed with the first 1 TiB per month free; active storage is billed around $0.02/GB/month, dropping to about $0.01/GB/month for tables untouched for 90+ days, with 10 GB of storage free monthly. Core capabilities include standard SQL support, streaming ingestion, materialized views, BigQuery ML (train and deploy machine learning models using SQL), BI Engine for fast dashboard queries, geospatial analysis, time travel and snapshots for data recovery, and native integration with the rest of the Google Cloud ecosystem (Cloud Storage, Dataflow, Looker, Vertex AI, Pub/Sub). BigQuery also supports federated queries against external sources (Cloud SQL, Spanner, Google Sheets) and cross-cloud analytics via BigQuery Omni for AWS and Azure data. More recently, Google has layered generative AI into the product through Gemini in BigQuery, which offers SQL/Python code generation, natural-language data exploration, and AI-powered data preparation; these AI features carry separate pricing tied to a Gemini Code Assist subscription or pay-as-you-go processing fees. BigQuery is used by data engineers, analysts, and data scientists at organizations of all sizes for business intelligence, log and event analytics, ELT pipelines, and ML feature engineering. Access is controlled through Google Cloud IAM, with support for column- and row-level security, data masking, and VPC Service Controls for enterprise governance. Because it is serverless, BigQuery automatically scales query execution across thousands of nodes, and users are only responsible for optimizing query design and partitioning/clustering strategy to control cost, not for managing clusters or nodes.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'fb9ac50a-5d37-4f5c-a9c6-8693d7deb334';

