-- ── Bill.com ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Bill.com (BILL) is a cloud-based accounts payable, receivable, and spend management platform that automates invoicing, approvals, and B2B payments for businesses and accounting firms.$q$, short_description),
  pricing_model = COALESCE($q$Subscription (per user, per month)$q$, pricing_model),
  starting_price = COALESCE($q$$49/user/month (AP & AR Essentials); Spend & Expense is free$q$, starting_price),
  founded_year = COALESCE(2006, founded_year),
  company_size = COALESCE($q$3,400+ employees$q$, company_size),
  headquarters = COALESCE($q$San Jose, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Bill.com (BILL): Pricing, Features & Review 2026$q$, seo_title),
  seo_meta_description = COALESCE($q$Bill.com automates AP, AR, and spend management. See 2026 pricing tiers, key features, integrations, pros, cons, and FAQs for BILL.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Bill.com, now operating as BILL Holdings, Inc. (NYSE: BILL), is a cloud-based financial operations platform that automates accounts payable (AP), accounts receivable (AR), and corporate spend and expense management for small and midsize businesses and the accounting firms that serve them. The company was founded in 2006 (originally as Cashboard, Inc.), completed its IPO on the New York Stock Exchange in December 2019, and is headquartered in San Jose, California, with roughly 3,400 employees as of 2026. BILL's core AP & AR product digitizes bill entry and invoicing, routes documents through configurable multi-step approval workflows, and executes payments via ACH, virtual card, check, or international wire, while also collecting W-9 tax forms and syncing two-way with accounting systems such as QuickBooks, Xero, NetSuite, Sage Intacct, and Microsoft Dynamics. AI-assisted invoice coding automatically extracts line-item data from incoming bills to speed up entry. The AP & AR product is sold in four tiers: Essentials at $49/user/month (manual CSV import, standard approval policies, six standard user roles), Team at $65/user/month (adds automatic two-way accounting sync and custom user roles), Corporate at $89/user/month (adds procurement tools like purchase orders and two-way matching plus custom approval policies), and Enterprise at custom pricing (multi-entity support, single sign-on, API access, and dual control for larger organizations). Separately, BILL Spend & Expense is offered free of charge and includes corporate and virtual cards, budget controls, automated expense tracking, a mobile app, and access to lines of credit ranging from $1,000 to $5 million, monetized instead through card interchange revenue. BILL also runs partner programs for accounting firms, offering wholesale AP & AR pricing with volume-based discounts and a free Spend & Expense partner tier with API access and no contracts. Beyond subscription fees, per-transaction charges apply to certain payment types such as instant transfers, international payments, and physical checks. Bill.com's vendor network connects payers and payees who already use the platform, reducing manual setup for recurring vendor relationships. The platform is aimed at small and midsize businesses, their finance teams, and the accounting/bookkeeping firms managing AP/AR on clients' behalf, positioning BILL as an alternative to manual, paper-based invoice and expense processes.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '19af63b9-f422-4e73-aa95-41f50d50e098';

