-- ── Billsby ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Billsby is a customizable subscription billing platform that automates recurring payments, dunning, and revenue reporting for SaaS and subscription businesses.$q$, short_description),
  pricing_model = COALESCE($q$Subscription + usage-based$q$, pricing_model),
  starting_price = COALESCE($q$$45/month (Core plan, plus 0.4% of revenue over $15,000/month)$q$, starting_price),
  founded_year = COALESCE(2016, founded_year),
  company_size = COALESCE($q$Small (private company, headcount not publicly disclosed)$q$, company_size),
  headquarters = COALESCE($q$London, United Kingdom$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Billsby: Pricing, Features & Review 2026$q$, seo_title),
  seo_meta_description = COALESCE($q$Billsby is subscription billing software for recurring revenue. See 2026 pricing plans, key features, integrations, pros, cons, and FAQs.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Billsby is a subscription billing and revenue management platform aimed at startups, small businesses, and enterprises running recurring-revenue models. The company is headquartered in London, United Kingdom, and was incorporated in the mid-2010s (public records show related entities registered between 2015 and 2017). Billsby positions itself as a customizable, developer-friendly alternative to building billing infrastructure in-house, offering unlimited products, plans, and customers on every plan rather than gating catalog size behind higher tiers. Core functionality covers recurring and usage-based subscription billing, invoice creation and management, online payment processing, dunning management for failed payments, cancellation and win-back flows, multi-currency support, and automated tax calculation. The platform also provides reporting and activity dashboards for tracking recurring revenue metrics, along with a public API and documentation for developers who want to embed billing logic directly into their own applications. Billsby is priced on a hybrid subscription-plus-usage model rather than flat per-seat pricing. The Core plan costs $45/month and includes all core features plus unlimited products, plans, and customers, with an additional 0.4% fee applied to monthly revenue processed above $15,000. The Pro plan costs $135/month and includes the same unlimited catalog capabilities plus priority support and more advanced reporting, with the 0.4% revenue-based fee kicking in above $50,000 in monthly revenue. This pricing structure means Billsby's effective cost scales with a customer's subscription revenue rather than staying fixed, which differentiates it from flat-fee competitors but requires customers to model in the percentage fee as revenue grows. The company's marketing emphasizes ease of integration, describing the platform as 'developer friendly' with dedicated API documentation, and offers a free way to get started before committing to a paid plan. Billsby's core audience is business owners, founders, and finance/product leaders at subscription-based companies who want to automate recurring billing operations, reduce involuntary churn through dunning management, and support multiple pricing plans and currencies without building custom billing infrastructure.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'abd1f2f3-8f2d-4fe4-a955-b465df5076cf';

