-- ── Birdeye ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Birdeye is an AI-powered customer experience and reputation management platform that helps multi-location businesses manage reviews, listings, messaging, and social media.$q$, short_description),
  pricing_model = COALESCE($q$Subscription (custom, quote-based)$q$, pricing_model),
  starting_price = COALESCE($q$Custom pricing (reported starting around $300/month per location)$q$, starting_price),
  founded_year = COALESCE(2012, founded_year),
  company_size = COALESCE($q$1,100-1,400 employees$q$, company_size),
  headquarters = COALESCE($q$Palo Alto, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Birdeye: Pricing, Features & Review 2026$q$, seo_title),
  seo_meta_description = COALESCE($q$Birdeye is an AI-driven reputation and customer experience platform. See 2026 pricing, key features, integrations, pros, cons, and FAQs.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Birdeye is a customer experience and reputation management platform founded in 2012 by brothers Naveen Gupta (CEO) and Neeraj Gupta (COO), and headquartered in Palo Alto, California, with additional offices across the United States, Europe, and Asia. The company has raised roughly $93 million in funding across multiple rounds, including a $60 million Series C led by Accel-KKR in March 2022, and reports estimated annual recurring revenue in the range of $100-150 million as of recent years. Birdeye employs an estimated 1,100-1,400 people globally, with the largest employee concentrations in India and the United States, and serves an estimated 80,000+ business customers, particularly multi-location brands such as healthcare groups, retail chains, franchises, and financial services offices. The platform centers on review and reputation management: monitoring and responding to reviews across Google, Facebook, and other third-party sites, requesting reviews from customers via automated campaigns, and surfacing sentiment insights. Beyond reviews, Birdeye offers business listings management to keep location data consistent across directories, social media management and publishing, customer survey tools, and a unified inbox for messaging and ticketing across channels like SMS, webchat, email, and social DMs. More recently, Birdeye has repositioned itself as an 'agentic marketing platform,' layering AI-driven automation and insights across these modules to help multi-location brands manage reputation and customer engagement at scale. Birdeye does not publish standardized self-serve pricing; instead it offers three named plans, Starter, Growth, and Dominate, sold through a custom quote process based on the number of business locations, with contracts typically structured annually. Third-party sources report starting costs around $300/month, though actual pricing depends heavily on location count and selected modules, and enterprise customers must contact Birdeye's sales team directly for a quote. The platform is primarily aimed at multi-location and franchise businesses that need centralized reputation, listings, and customer engagement management across many storefronts or offices, rather than single-location small businesses, though smaller businesses can also use scaled-down configurations.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '96e7ec06-f2ec-4702-94ef-ddc083739f48';

