  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$bitmagnet: Self-Hosted Torrent Indexer & DHT Crawler$q$, seo_title),
  seo_meta_description = COALESCE($q$bitmagnet is a free, open-source, self-hosted BitTorrent indexer with DHT crawling, GraphQL API, and Sonarr/Radarr integration.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$bitmagnet is a free, open-source, self-hosted BitTorrent indexer, DHT crawler, content classifier, and torrent search engine, distributed under the MIT license via GitHub (bitmagnet-io/bitmagnet). As of mid-2026 the project has accumulated roughly 4,200 GitHub stars and 242 forks across more than 50 releases, with the latest tagged release around v0.10.0 (published March 2025); the project describes itself as being in alpha, meaning users should expect occasional bugs and possible breaking changes to its API or database schema before a stable 1.0 release. The application is built primarily in Go for its backend, with a TypeScript/React web frontend, and stores indexed torrent metadata in a PostgreSQL database. Its core function is crawling the BitTorrent distributed hash table (DHT) network to discover active info hashes, then requesting and storing the associated torrent metadata (file names, sizes, categories). bitmagnet further enriches this raw metadata by classifying content and attempting to match it to known movies, TV shows, music, and other media, making the indexed data more useful for search and automation than a raw DHT crawl would be. Users interact with bitmagnet through a self-hosted web UI for browsing and searching indexed torrents, or programmatically through a GraphQL API for building custom integrations. A key use case is integration with the 'Servarr' ecosystem of self-hosted media automation tools, Sonarr, Radarr, Lidarr, and Prowlarr, where bitmagnet functions as a custom torrent indexer/source that these tools can query automatically when searching for content to download. Because it crawls the public DHT network directly rather than relying on third-party tracker or indexer websites, bitmagnet can discover torrents without depending on external, often unreliable public indexer sites. Deployment is via Docker, with an official Dockerfile and docker-compose.yml provided in the repository, which is the standard installation path for most self-hosters running it alongside other home-server or NAS-based services. As a self-hosted, MIT-licensed tool, bitmagnet has no company, pricing, or commercial support structure behind it; it is maintained as a community open-source project, and users are responsible for their own hosting, updates, and compliance with applicable laws regarding torrent content in their jurisdiction.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'ea9bc5c8-40c1-49f7-8e54-f0816195bf57';

