-- ── bittorrent-tracker ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$bittorrent-tracker is an open-source Node.js library providing client and server implementations of BitTorrent HTTP, UDP, and WebSocket trackers, used by WebTorrent.$q$, short_description),
  pricing_model = COALESCE($q$Free (open source)$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(NULL, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$bittorrent-tracker: Node.js BitTorrent Tracker Library$q$, seo_title),
  seo_meta_description = COALESCE($q$bittorrent-tracker is a free, open-source Node.js library for building BitTorrent tracker clients and servers, used by WebTorrent.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$bittorrent-tracker is a free, open-source Node.js package that implements both the client and server sides of the BitTorrent tracker protocol. It is maintained by Feross Aboukhadijeh and WebTorrent, LLC, distributed under the MIT license, and hosted on GitHub under the webtorrent organization (webtorrent/bittorrent-tracker). As of 2026 the repository has around 1,900 stars and 330 forks across 35 tagged releases, with the latest version at v11.2.3, and the codebase is almost entirely JavaScript. A BitTorrent tracker is a web service that BitTorrent clients query to discover peers participating in the same torrent 'swarm'; the tracker itself does not transfer file data, it only coordinates peer discovery. This library implements support for all mainstream tracker transport types: HTTP trackers, UDP trackers (as defined in BEP 15), and WebSocket-based WebTorrent trackers (needed for browser-based peer-to-peer transfers, since browsers cannot make raw UDP or TCP connections), with support for both IPv4 and IPv6 and the tracker 'scrape' extension for querying statistics on multiple torrents at once. The package can be installed via `npm install bittorrent-tracker` and exposes both a Client class (for BitTorrent applications that need to announce to trackers and receive peer lists) and a Server class (for standing up a tracker service that other clients can announce to, complete with a web-based statistics interface). It is battle-tested through use in production by WebTorrent, a widely used streaming torrent client and browser-based P2P engine, as well as other torrent-related Node.js tools like peerflix. The library includes an offline-runnable automated test suite, making it straightforward to validate changes without needing to connect to live tracker infrastructure. As a foundational networking library rather than a hosted product, bittorrent-tracker has no pricing, subscription, or company behind it beyond its open-source maintainers; developers embed it directly into their own applications (media players, file-sharing tools, P2P CDNs) to add tracker client or server capability, and are responsible for their own deployment, scaling, and compliance considerations when running a tracker server themselves.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '2656ef1b-64da-4cfd-a088-8db929a97a0a';

