INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fb9ac50a-5d37-4f5c-a9c6-8693d7deb334', $q$Serverless architecture$q$, $q$No clusters or servers to provision, patch, or resize; Google Cloud automatically scales query execution.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fb9ac50a-5d37-4f5c-a9c6-8693d7deb334', $q$Separate storage and compute billing$q$, $q$Pay for data scanned and data stored independently, choosing on-demand or flat-rate capacity pricing.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fb9ac50a-5d37-4f5c-a9c6-8693d7deb334', $q$BigQuery ML$q$, $q$Train and run machine learning models directly with SQL, without exporting data to a separate ML platform.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fb9ac50a-5d37-4f5c-a9c6-8693d7deb334', $q$Streaming ingestion$q$, $q$Load and query data in near real time for event and log analytics use cases.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fb9ac50a-5d37-4f5c-a9c6-8693d7deb334', $q$BigQuery Omni$q$, $q$Run BigQuery analytics on data stored in AWS S3 and Azure Blob Storage without migrating it.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fb9ac50a-5d37-4f5c-a9c6-8693d7deb334', $q$Gemini in BigQuery$q$, $q$AI-assisted SQL and Python code generation, and natural-language querying, layered on top of core analytics.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fb9ac50a-5d37-4f5c-a9c6-8693d7deb334', $q$Fine-grained security$q$, $q$Column- and row-level security, data masking, and integration with Google Cloud IAM and VPC Service Controls.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fb9ac50a-5d37-4f5c-a9c6-8693d7deb334', $q$Scales automatically to very large datasets without infrastructure management$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fb9ac50a-5d37-4f5c-a9c6-8693d7deb334', $q$Pay-per-query pricing can be cost-effective for intermittent or bursty workloads$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fb9ac50a-5d37-4f5c-a9c6-8693d7deb334', $q$Deep integration with the wider Google Cloud and Looker/Vertex AI ecosystem$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fb9ac50a-5d37-4f5c-a9c6-8693d7deb334', $q$Built-in machine learning (BigQuery ML) reduces the need for separate ML tooling$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fb9ac50a-5d37-4f5c-a9c6-8693d7deb334', $q$On-demand cost can be unpredictable and spike with poorly optimized queries scanning large tables$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fb9ac50a-5d37-4f5c-a9c6-8693d7deb334', $q$Steep learning curve for cost optimization (partitioning, clustering, slot reservations)$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fb9ac50a-5d37-4f5c-a9c6-8693d7deb334', $q$Best-in-class experience is somewhat tied to the Google Cloud ecosystem$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fb9ac50a-5d37-4f5c-a9c6-8693d7deb334', $q$AI features (Gemini in BigQuery) require additional, separately metered spend$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fb9ac50a-5d37-4f5c-a9c6-8693d7deb334', $q$Is BigQuery free to use?$q$, $q$BigQuery has a free tier: 1 TiB of on-demand query processing and 10 GB of active storage per month at no cost, with no credit card required to start on Google Cloud's free tier.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fb9ac50a-5d37-4f5c-a9c6-8693d7deb334', $q$How is BigQuery priced?$q$, $q$BigQuery bills storage and compute separately. On-demand compute is charged per terabyte of data a query scans (around $6.25/TiB), while active storage is billed at roughly $0.02/GB/month. Capacity-based 'editions' with autoscaling compute capacity are also available for predictable, high-volume workloads.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fb9ac50a-5d37-4f5c-a9c6-8693d7deb334', $q$Does BigQuery support machine learning?$q$, $q$Yes. BigQuery ML lets users create, train, and deploy machine learning models using standard SQL statements directly against data already stored in BigQuery, without exporting it to a separate platform.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fb9ac50a-5d37-4f5c-a9c6-8693d7deb334', $q$Can BigQuery query data stored outside Google Cloud?$q$, $q$Yes, via BigQuery Omni, which runs BigQuery's query engine against data stored in AWS S3 or Azure Blob Storage without requiring the data to be moved into Google Cloud.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fb9ac50a-5d37-4f5c-a9c6-8693d7deb334', $q$Who typically uses BigQuery?$q$, $q$Data engineers, analysts, and data scientists at companies of all sizes use BigQuery as a central analytics warehouse for business intelligence, log/event analysis, and ELT pipelines feeding dashboards and ML models.$q$, 4, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fb9ac50a-5d37-4f5c-a9c6-8693d7deb334', $q$Centralized analytics warehouse$q$, $q$Consolidate data from multiple sources into a single warehouse for BI dashboards and reporting.$q$, $q$Data engineering and analytics teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fb9ac50a-5d37-4f5c-a9c6-8693d7deb334', $q$Real-time event analytics$q$, $q$Stream application, IoT, or log data into BigQuery for near real-time querying and alerting.$q$, $q$Engineering and operations teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fb9ac50a-5d37-4f5c-a9c6-8693d7deb334', $q$In-warehouse machine learning$q$, $q$Train and deploy predictive models with BigQuery ML using SQL, avoiding data movement to a separate ML platform.$q$, $q$Data scientists and analysts$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('fb9ac50a-5d37-4f5c-a9c6-8693d7deb334', $q$On-Demand$q$, $q$$6.25 per TiB processed (first 1 TiB/month free)$q$, $q$Usage-based$q$, NULL, $q$["Pay only for data scanned","1 TiB free query processing/month","10 GB free storage/month"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('fb9ac50a-5d37-4f5c-a9c6-8693d7deb334', $q$Capacity Editions (Standard/Enterprise/Enterprise Plus)$q$, $q$Autoscaling capacity-based pricing, custom$q$, $q$Pay-as-you-go or 1/3-year commitment$q$, NULL, $q$["Predictable capacity-based compute","Autoscaling capacity","Discounts for annual/multi-year commitments"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fb9ac50a-5d37-4f5c-a9c6-8693d7deb334', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$BigQuery is Google Cloud's serverless enterprise data warehouse, first announced in 2010 and generally available since late 2011. It is built on Dremel, the distributed query engine Google originally developed for internal use, and is designed to run interactive SQL analytics over datasets that span gigabytes to petabytes.$q$, $q$Because storage and compute are billed and scaled separately, BigQuery requires no cluster sizing or server management. Teams write standard SQL, and Google Cloud handles distributing the query across its infrastructure, making it a popular choice for centralized analytics warehouses feeding BI tools, data science notebooks, and downstream applications.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fb9ac50a-5d37-4f5c-a9c6-8693d7deb334', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$BigQuery supports standard ANSI SQL, streaming and batch ingestion, materialized views, and native machine learning through BigQuery ML, which lets analysts train models using SQL syntax alone. BI Engine accelerates dashboard-style queries with in-memory caching.$q$, $q$The platform also offers BigQuery Omni for querying data stored in AWS and Azure without moving it, federated queries against operational databases and Google Sheets, geospatial functions, and time-travel snapshots that let teams recover or query historical table states. Gemini in BigQuery adds AI-assisted SQL generation and natural-language data exploration on top of the core engine.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fb9ac50a-5d37-4f5c-a9c6-8693d7deb334', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$BigQuery uses consumption-based pricing split between storage and compute. On-demand compute is billed per terabyte of data scanned by a query, with a free monthly allowance; storage is billed per gigabyte per month, with a lower rate applied to tables that haven't been modified in 90 days.$q$, $q$For predictable, high-volume workloads, BigQuery offers capacity-based 'editions' (Standard, Enterprise, Enterprise Plus) with autoscaling compute capacity and optional one- or three-year commitments for discounted rates. AI features such as Gemini in BigQuery are priced separately from core query and storage costs.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('fb9ac50a-5d37-4f5c-a9c6-8693d7deb334', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('fb9ac50a-5d37-4f5c-a9c6-8693d7deb334', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('fb9ac50a-5d37-4f5c-a9c6-8693d7deb334', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('fb9ac50a-5d37-4f5c-a9c6-8693d7deb334', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('fb9ac50a-5d37-4f5c-a9c6-8693d7deb334', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('19af63b9-f422-4e73-aa95-41f50d50e098', $q$AP automation$q$, $q$Digitizes bill entry with AI-assisted coding and routes invoices through configurable approval workflows.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('19af63b9-f422-4e73-aa95-41f50d50e098', $q$AR automation$q$, $q$Creates and sends invoices, and accepts online payments to speed up customer collections.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('19af63b9-f422-4e73-aa95-41f50d50e098', $q$Flexible payment rails$q$, $q$Pay vendors via ACH, virtual card, paper check, or international wire from a single platform.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('19af63b9-f422-4e73-aa95-41f50d50e098', $q$Accounting sync$q$, $q$Two-way integration with QuickBooks, Xero, NetSuite, Sage Intacct, and Microsoft Dynamics.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('19af63b9-f422-4e73-aa95-41f50d50e098', $q$BILL Spend & Expense$q$, $q$Free corporate and virtual card program with budgeting, expense tracking, and credit access up to $5M.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('19af63b9-f422-4e73-aa95-41f50d50e098', $q$Vendor network$q$, $q$Connects payers and payees already on BILL to simplify recurring vendor payment setup.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('19af63b9-f422-4e73-aa95-41f50d50e098', $q$Procurement tools$q$, $q$Purchase orders and two-way matching available on Corporate and Enterprise tiers.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('19af63b9-f422-4e73-aa95-41f50d50e098', $q$Accountant partner program$q$, $q$Wholesale pricing and API access for accounting firms managing AP/AR for multiple clients.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('19af63b9-f422-4e73-aa95-41f50d50e098', $q$Consolidates AP, AR, and spend/expense management in one platform$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('19af63b9-f422-4e73-aa95-41f50d50e098', $q$Strong two-way integrations with major accounting systems$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('19af63b9-f422-4e73-aa95-41f50d50e098', $q$Free Spend & Expense tier with no subscription cost$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('19af63b9-f422-4e73-aa95-41f50d50e098', $q$Dedicated accountant/bookkeeper partner program with wholesale pricing$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('19af63b9-f422-4e73-aa95-41f50d50e098', $q$Per-user subscription pricing plus per-transaction fees can add up for larger teams$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('19af63b9-f422-4e73-aa95-41f50d50e098', $q$Advanced procurement and enterprise features are gated behind higher tiers$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('19af63b9-f422-4e73-aa95-41f50d50e098', $q$Enterprise pricing is not publicly listed and requires a custom quote$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('19af63b9-f422-4e73-aa95-41f50d50e098', $q$Some payment types (checks, international, instant transfers) carry extra fees$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('19af63b9-f422-4e73-aa95-41f50d50e098', $q$How much does Bill.com cost?$q$, $q$BILL's AP & AR plans start at $49/user/month for Essentials, rising to $65/user/month for Team and $89/user/month for Corporate, with custom Enterprise pricing. BILL Spend & Expense has no subscription fee.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('19af63b9-f422-4e73-aa95-41f50d50e098', $q$Does Bill.com integrate with QuickBooks and Xero?$q$, $q$Yes. Team-tier and higher AP & AR plans include automatic two-way sync with QuickBooks and Xero, and Enterprise supports NetSuite, Sage Intacct, and Microsoft Dynamics.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('19af63b9-f422-4e73-aa95-41f50d50e098', $q$Is there a free version of Bill.com?$q$, $q$BILL Spend & Expense, the corporate card and expense management product, is free to use; the AP & AR automation product requires a paid subscription.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('19af63b9-f422-4e73-aa95-41f50d50e098', $q$When was Bill.com founded and did it go public?$q$, $q$Bill.com was founded in 2006 and completed its IPO on the New York Stock Exchange in December 2019 under the ticker BILL.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('19af63b9-f422-4e73-aa95-41f50d50e098', $q$Who is Bill.com designed for?$q$, $q$Bill.com serves small and midsize businesses managing their own finance operations, as well as accounting and bookkeeping firms handling AP/AR for multiple clients through its partner program.$q$, 4, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('19af63b9-f422-4e73-aa95-41f50d50e098', $q$Accounts payable automation$q$, $q$Digitize bill capture, route approvals, and pay vendors electronically instead of using manual, paper-based processes.$q$, $q$SMB finance and accounting teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('19af63b9-f422-4e73-aa95-41f50d50e098', $q$Client AP/AR management for accounting firms$q$, $q$Manage bill pay and invoicing across multiple clients from one dashboard with wholesale pricing.$q$, $q$Bookkeepers and accounting firms$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('19af63b9-f422-4e73-aa95-41f50d50e098', $q$Corporate card and expense control$q$, $q$Issue virtual/physical cards, set budgets, and automate expense tracking without a subscription fee.$q$, $q$Finance teams managing employee spend$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('19af63b9-f422-4e73-aa95-41f50d50e098', $q$Essentials$q$, $q$$49/user/month$q$, $q$Monthly, per user$q$, NULL, $q$["Manual CSV integration","Approval workflows","ACH/card/check payments","AI invoice coding","6 standard user roles"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('19af63b9-f422-4e73-aa95-41f50d50e098', $q$Team$q$, $q$$65/user/month$q$, $q$Monthly, per user$q$, NULL, $q$["Automatic 2-way sync with QuickBooks/Xero","Custom user roles","All Essentials features"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('19af63b9-f422-4e73-aa95-41f50d50e098', $q$Corporate$q$, $q$$89/user/month$q$, $q$Monthly, per user$q$, NULL, $q$["Procurement (purchase orders, 2-way matching)","Custom approval policies","Sync with multiple accounting platforms"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('19af63b9-f422-4e73-aa95-41f50d50e098', $q$Enterprise$q$, $q$Custom$q$, $q$Contact for quote$q$, NULL, $q$["Multi-entity support","Single sign-on","API access","Syncs with NetSuite, Sage Intacct, Microsoft Dynamics"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('19af63b9-f422-4e73-aa95-41f50d50e098', $q$Spend & Expense$q$, $q$Free$q$, $q$No subscription fee$q$, NULL, $q$["Corporate and virtual cards","Budget management","Expense tracking","Credit access up to $5M"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('19af63b9-f422-4e73-aa95-41f50d50e098', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Bill.com (now BILL Holdings, Inc., NYSE: BILL) was founded in 2006 and is headquartered in San Jose, California. The company automates back-office finance workflows, primarily accounts payable and receivable, for small and midsize businesses and the accounting firms that manage their books.$q$, $q$BILL went public on the NYSE in December 2019 and has since expanded from AP/AR automation into corporate card and expense management (BILL Spend & Expense) and procurement, positioning itself as a broader financial operations platform rather than a single-purpose bill-pay tool.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('19af63b9-f422-4e73-aa95-41f50d50e098', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The AP & AR product digitizes invoice entry with AI-assisted coding, routes bills through configurable multi-step approval workflows, and pays vendors via ACH, virtual card, check, or international payment rails, while two-way syncing with accounting systems like QuickBooks, Xero, NetSuite, and Sage Intacct.$q$, $q$BILL Spend & Expense, offered at no subscription cost, provides corporate and virtual cards, budget controls, automated expense capture, and access to business credit lines. Higher AP & AR tiers add procurement tools such as purchase orders and two-way matching, plus enterprise features like single sign-on and API access.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('19af63b9-f422-4e73-aa95-41f50d50e098', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$BILL's AP & AR product is priced per user per month across four tiers: Essentials ($49), Team ($65), Corporate ($89), and Enterprise (custom quote). Each tier unlocks deeper accounting integrations, customization, and procurement functionality than the last.$q$, $q$BILL Spend & Expense carries no subscription fee and monetizes through card interchange. Regardless of plan, certain payment methods (checks, instant transfers, international payments) incur per-transaction fees on top of the subscription.$q$]::text[], 2);
