INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('19af63b9-f422-4e73-aa95-41f50d50e098', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
